+import type { AnyColumn } from '~/column.ts';
+import { is } from '~/entity.ts';
+import { SQL, sql, type SQLWrapper } from '../sql.ts';
+
+type ExpressionData<T extends SQLWrapper> = T extends AnyColumn ? T['_']['data'] : T extends SQL<infer TData> ? TData : unknown;
+type WindowExpression = SQLWrapper;
+export type WindowSpec = {
+	partitionBy?: WindowExpression | WindowExpression[];
+	orderBy?: WindowExpression | WindowExpression[];
+	frame?: SQL;
+};
+
+type FrameBoundary = { readonly kind: 'unbounded preceding' | 'current row' | 'unbounded following' | 'preceding' | 'following'; readonly value?: number };
+export const unboundedPreceding: FrameBoundary = { kind: 'unbounded preceding' };
+export const currentRow: FrameBoundary = { kind: 'current row' };
+export const unboundedFollowing: FrameBoundary = { kind: 'unbounded following' };
+
+function numberedBoundary(kind: 'preceding' | 'following', value: number): FrameBoundary {
+	if (!Number.isInteger(value) || value < 0) throw new Error(`${kind}() requires a non-negative integer; received ${value}`);
+	return { kind, value };
+}
+export function preceding(value: number): FrameBoundary { return numberedBoundary('preceding', value); }
+export function following(value: number): FrameBoundary { return numberedBoundary('following', value); }
+
+function boundaryOrder(boundary: FrameBoundary): number {
+	if (boundary.kind === 'unbounded preceding') return -Infinity;
+	if (boundary.kind === 'unbounded following') return Infinity;
+	if (boundary.kind === 'current row') return 0;
+	return boundary.kind === 'preceding' ? -boundary.value! : boundary.value!;
+}
+function frame(kind: 'rows' | 'range', spec: { from: FrameBoundary; to: FrameBoundary }): SQL {
+	if (boundaryOrder(spec.from) > boundaryOrder(spec.to)) throw new Error('Window frame "from" boundary must not be ordered after "to"');
+	const render = (boundary: FrameBoundary) => boundary.value === undefined ? boundary.kind : `${boundary.value} ${boundary.kind}`;
+	return sql.raw(`${kind} between ${render(spec.from)} and ${render(spec.to)}`);
+}
+export function rows(spec: { from: FrameBoundary; to: FrameBoundary }): SQL { return frame('rows', spec); }
+export function range(spec: { from: FrameBoundary; to: FrameBoundary }): SQL { return frame('range', spec); }
+
+function windowSpec(spec: WindowSpec): SQL {
+	const partitionBy = spec.partitionBy === undefined ? [] : Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy];
+	const orderBy = spec.orderBy === undefined ? [] : Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy];
+	return sql`${partitionBy.length ? sql`partition by ${sql.join(partitionBy, sql`, `)} ` : undefined}${orderBy.length ? sql`order by ${sql.join(orderBy, sql`, `)} ` : undefined}${spec.frame}`;
+}
+
+export class WindowFunction<T> extends SQL<T> {
+	over(spec: WindowSpec): SQL<T>;
+	over(windowName: string): SQL<T>;
+	over(specOrName: WindowSpec | string): SQL<T> {
+		return typeof specOrName === 'string'
+			? sql`${this} over ${sql.identifier(specOrName)}`.mapWith(this.decoder)
+			: sql`${this} over (${windowSpec(specOrName)})`.mapWith(this.decoder);
+	}
+}
+function fn<T>(name: string, args: SQLWrapper[] = []): WindowFunction<T> {
+	return new WindowFunction<T>([sql.raw(`${name}(`), sql.join(args, sql`, `), sql.raw(')')]);
+}
+function positiveInteger(functionName: string, value: number): void {
+	if (!Number.isInteger(value) || value <= 0) throw new Error(`${functionName}() requires a positive integer; received ${value}`);
+}
+const positional = (value: number) => sql.raw(String(value));
+
+export const rowNumber = () => fn<number>('row_number');
+export const rank = () => fn<number>('rank');
+export const denseRank = () => fn<number>('dense_rank');
+export function ntile(buckets: number): WindowFunction<number> { positiveInteger('ntile', buckets); return fn('ntile', [positional(buckets)]); }
+export const percentRank = () => fn<number>('percent_rank');
+export const cumeDist = () => fn<number>('cume_dist');
+export function lag<T extends SQLWrapper>(expression: T): WindowFunction<ExpressionData<T> | null>;
+export function lag<T extends SQLWrapper>(expression: T, offset: number, defaultValue: ExpressionData<T>): WindowFunction<ExpressionData<T>>;
+export function lag<T extends SQLWrapper>(expression: T, offset?: number, defaultValue?: ExpressionData<T>): WindowFunction<ExpressionData<T> | null> { return fn('lag', [expression, ...(offset === undefined ? [] : [positional(offset)]), ...(defaultValue === undefined ? [] : [sql.param(defaultValue)])]); }
+export function lead<T extends SQLWrapper>(expression: T): WindowFunction<ExpressionData<T> | null>;
+export function lead<T extends SQLWrapper>(expression: T, offset: number, defaultValue: ExpressionData<T>): WindowFunction<ExpressionData<T>>;
+export function lead<T extends SQLWrapper>(expression: T, offset?: number, defaultValue?: ExpressionData<T>): WindowFunction<ExpressionData<T> | null> { return fn('lead', [expression, ...(offset === undefined ? [] : [positional(offset)]), ...(defaultValue === undefined ? [] : [sql.param(defaultValue)])]); }
+export function firstValue<T extends SQLWrapper>(expression: T): WindowFunction<ExpressionData<T> | null> { return fn('first_value', [expression]); }
+export function lastValue<T extends SQLWrapper>(expression: T): WindowFunction<ExpressionData<T> | null> { return fn('last_value', [expression]); }
+export function nthValue<T extends SQLWrapper>(expression: T, nth: number): WindowFunction<ExpressionData<T> | null> { positiveInteger('nthValue', nth); return fn('nth_value', [expression, positional(nth)]); }
+export function windowSum(expression: SQLWrapper): WindowFunction<string | null> { return fn('sum', [expression]); }
+export function windowAvg(expression: SQLWrapper): WindowFunction<string | null> { return fn('avg', [expression]); }
+export function windowMin<T extends SQLWrapper>(expression: T): WindowFunction<ExpressionData<T> | string | null> { return fn('min', [expression]); }
+export function windowMax<T extends SQLWrapper>(expression: T): WindowFunction<ExpressionData<T> | string | null> { return fn('max', [expression]); }
+export function windowCount(expression?: SQLWrapper): WindowFunction<number> { return fn('count', expression ? [expression] : [sql.raw('*')]); }
